Certainly! Here is a simple HTML game—**"Guess the Number"**—that you can use as a standalone HTML file. The user tries to guess a randomly chosen number between 1 and 100. The game provides feedback if the guess is too high, too low, or correct.

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Guess the Number Game</title>
  <style>
    body { font-family: Arial, sans-serif; text-align: center; margin-top: 60px; }
    input[type="number"] { width: 60px; padding: 5px; }
    #result { margin: 20px; font-weight: bold; }
    #guesses { color: #333; }
  </style>
</head>
<body>
  <h1>Guess the Number!</h1>
  <p>I'm thinking of a number between 1 and 100. Can you guess it?</p>
  <input type="number" id="guessInput" min="1" max="100">
  <button onclick="checkGuess()">Guess</button>
  <button onclick="restartGame()">Restart</button>
  <div id="result"></div>
  <div id="guesses"></div>
  <script>
    let target = Math.floor(Math.random() * 100) + 1;
    let attempts = 0;
    let history = [];
    function checkGuess() {
      const guess = parseInt(document.getElementById('guessInput').value);
      if (!guess || guess < 1 || guess > 100) {
        document.getElementById('result').textContent = "Enter a valid number (1-100).";
        return;
      }
      attempts++;
      history.push(guess);
      if (guess === target) {
        document.getElementById('result').textContent = `🎉 Correct! You guessed it in ${attempts} tries.`;
      } else if (guess < target) {
        document.getElementById('result').textContent = "Too low! Try again.";
      } else {
        document.getElementById('result').textContent = "Too high! Try again.";
      }
      document.getElementById('guesses').textContent = "Your guesses: " + history.join(', ');
    }
    function restartGame() {
      target = Math.floor(Math.random() * 100) + 1;
      attempts = 0;
      history = [];
      document.getElementById('result').textContent = "";
      document.getElementById('guesses').textContent = "";
      document.getElementById('guessInput').value = "";
    }
  </script>
</body>
</html>
```

**How to use:**  
1. Copy all of the above code into a new file and save it as `guess.html`.
2. Open `guess.html` in your web browser.
3. Play the game!

